type TicketTemplateFunc func(context.Context, *migrations.TicketTemplateMutation) (migrations.Value, error)

// Mutate calls f(ctx, m).
func (f TicketTemplateFunc) Mutate(ctx context.Context, m migrations.Mutation) (migrations.Value, error) {
	if mv, ok := m.(*migrations.TicketTemplateMutation); ok {
		return f(ctx, mv)
	}
	return nil, fmt.Errorf("unexpected mutation type %T. expect *migrations.TicketTemplateMutation", m)
}

